'use strict';

const NodeCache = require('node-cache');
const uaaUtils = require('../utils/uaa-utils');
const tokenUtils = require('../utils/token-utils');
const request = require('../utils/request-utils');
const {getValidatedEnvInt} = require('../utils/env-utils');

const ownappCacheTTL = getValidatedEnvInt('OWNAPP_CACHE_TTL', 600);
const ownappCache = new NodeCache({stdTTL: ownappCacheTTL, checkperiod: ownappCacheTTL + 20});

module.exports = {
  isLoginCallback: function (req) {
    return (req.url.includes(req.routerConfig.appConfig.login.callbackEndpoint) && req.method === 'GET' && !(isSessionExists(req)));
  }
};

module.exports.validateXForwardedHost = async function(req) {
  if ((!req.routerConfig) || (req.routerConfig && req.routerConfig.checkXForwardedHostInLoginCallback !== true)) {
    return;
  }

  const authType = (req.query && req.query.authType) || 'xsuaa';
  if (authType === 'ias') {
    return;
  }

  const xForwardedHost = req.headers && req.headers['x-forwarded-host'];
  if (!xForwardedHost) {
    return;
  }

  const uaaOptions = await new Promise((resolve, reject) => {
    uaaUtils.getUaaConfig(req, (err, opts) => err ? reject(new Error('Failed to get UAA config: ' + err)) : resolve(opts));
  });

  const ownappUrl = uaaOptions.apiurl + '/sap/rest/authorization/v2/ownapp?hideDetails=true';
  let ownappData = ownappCache.get(ownappUrl);
  if (!ownappData) {
    const serviceName = uaaOptions.label || 'xsuaa';
    const accessToken = await tokenUtils.getAndLoadClientCredentialsToken(req, uaaOptions, serviceName);
    const {error, response, body} = await request.axiosRequest('get', {
      url: ownappUrl,
      headers: {'Authorization': 'Bearer ' + accessToken}
    });
    if (error || !response || response.statusCode !== 200) {
      const errorMessage = (error && error.message) || (response && response.statusMessage);
      throw new Error('Failed to fetch ownapp data ' + errorMessage);
    }
    try {
      ownappData = JSON.parse(body);
      ownappCache.set(ownappUrl, ownappData);
    } catch (e) {
      throw new Error('Failed to parse ownapp response ' + e.message);
    }
  }

  const redirectUris = ownappData && ownappData['oauth2-configuration'] && ownappData['oauth2-configuration']['redirect-uris'];
  if (!redirectUris || !Array.isArray(redirectUris) || redirectUris.length === 0) {
    const err = new Error(`x-forwarded-host validation failed: missing redirect-uris.
    redirect-uris configuration is mandatory when x-forwarded-host is provided and CHECK_X_FORWARDED_HOST_IN_LOGIN_CALLBACK is true`);
    err.status = 400;
    throw err;
  }
  const wildcardPattern = /\*\.cfapps\./;
  const matched = redirectUris.some(uri => wildcardPattern.test(uri));
  if (matched) {
    const err = new Error('x-forwarded-host validation failed: redirect-uris contains invalid redirect URI. ' +
      'redirect-uris must not contain the wildcard pattern *.cfapps. when x-forwarded-host is provided and CHECK_X_FORWARDED_HOST_IN_LOGIN_CALLBACK is true');
    err.status = 400;
    throw err;
  }
};

function isSessionExists(req) {
  return req.session && req.session.user && req.session.user.token && req.session.user.token.expiryDate > Date.now();
}
